class Solution:
    def findTargetSumWays(self, nums: List[int], target: int) -> int:
        s = sum(nums)
        if (target + s) % 2 or abs(target) > s: return 0
        t = (target + s) // 2
        dp = [0] * (t + 1)
        dp[0] = 1
        for x in nums:
            for j in range(t, x - 1, -1):
                dp[j] += dp[j - x]
        return dp[t]

