int findTargetSumWays(int* nums, int n, int target) {
    long s=0; for(int i=0;i<n;i++) s+=nums[i];
    if((target+s)%2||abs(target)>s) return 0;
    int t=(target+s)/2;
    int* dp=calloc(t+1,sizeof(int)); dp[0]=1;
    for(int i=0;i<n;i++) for(int j=t;j>=nums[i];j--) dp[j]+=dp[j-nums[i]];
    int ans=dp[t]; free(dp); return ans;
}
